#!/usr/bin/env python3
"""Quorum-read race and a leader-based linearizable register."""
from dataclasses import dataclass, field
from typing import List


@dataclass
class Replica:
    name: str
    value: int = 0
    inbox: List[int] = field(default_factory=list)
    durable: int = 0

    def apply_one(self):
        if self.inbox:
            self.value = self.inbox.pop(0)


class LeaderlessStore:
    def __init__(self):
        self.replicas = [Replica("r0"), Replica("r1"), Replica("r2")]

    def write_async(self, v: int):
        for replica in self.replicas:
            replica.inbox.append(v)

    def quorum_read(self, idxs: List[int]) -> int:
        return max(self.replicas[i].value for i in idxs)


def reproduce_bug():
    store = LeaderlessStore()
    store.write_async(1)
    store.replicas[0].apply_one()
    a = store.quorum_read([0, 1])
    b = store.quorum_read([1, 2])
    print(f"A={a} B={b}")
    assert a == 1 and b == 0
    print("BUG: nonlinearizable (A saw 1 then B saw 0)")


class LeaderStore:
    """A three-replica register whose committed reads go through r0."""

    def __init__(self):
        self.replicas = [Replica("r0"), Replica("r1"), Replica("r2")]
        self.leader = 0
        self.epoch = 1
        self._install_leadership()

    def _install_leadership(self):
        for replica in self.replicas:
            replica.leader = self.leader
            replica.epoch = self.epoch

    def _has_leadership_quorum(self) -> bool:
        acknowledgements = sum(
            getattr(replica, "leader", None) == self.leader
            and getattr(replica, "epoch", None) == self.epoch
            for replica in self.replicas
        )
        return acknowledgements >= 2

    def write(self, v: int):
        if not self._has_leadership_quorum():
            raise RuntimeError("leader is not confirmed for this epoch")

        for replica in self.replicas:
            replica.inbox.append(v)
        for replica in self.replicas[:2]:
            replica.durable = v
        if sum(replica.durable == v for replica in self.replicas) < 2:
            raise RuntimeError("write did not reach a durable majority")
        self.replicas[self.leader].value = v

    def linearizable_read(self) -> int:
        if not self._has_leadership_quorum():
            raise RuntimeError("this node is not leader for the current epoch")
        return self.replicas[self.leader].value

    def follower_read(self, idx: int) -> int:
        """Diagnostic API only: it intentionally permits stale values."""
        return self.replicas[idx].value


def replay_with_leader():
    store = LeaderStore()
    store.write(1)
    store.replicas[1].apply_one()  # Partial delivery; r2 still has value 0.
    a = store.linearizable_read()
    b = store.linearizable_read()
    print(f"leader reads: A={a} B={b}")
    assert a == b == 1

    stale = store.follower_read(2)
    print(f"lagging follower read: {stale}")
    assert stale == 0


if __name__ == "__main__":
    reproduce_bug()
    replay_with_leader()
```

## Write-up

Quorum intersection alone does not impose one read order: different quorums can observe different replica apply states. The leader serializes reads and writes after epoch confirmation, but can become a bottleneck, and a minority partition cannot serve linearizable operations.

`follower_read` is not linearizable because it bypasses the leader and can return a stale replica value.

