#!/usr/bin/env python3
from dataclasses import dataclass, field
from typing import Any, Dict, Optional

@dataclass
class Node:
    id: str
    decided: Optional[Any] = None
    crashed: bool = False
    voted_epoch: int = -1
    voted_for: Optional[str] = None

def buggy_decide(nodes, proposals: Dict[str, str]):
    # each node "decides" its own proposal locally — split brain
    for n in nodes:
        n.decided = proposals[n.id]
    return {n.id: n.decided for n in nodes}


class ConsensusCluster:
    """A small single-value consensus cluster with epoch-based leadership."""

    def __init__(self, nodes, proposals: Optional[Dict[str, Any]] = None):
        self.nodes = list(nodes)
        self.by_id = {node.id: node for node in self.nodes}
        self.proposals = dict(proposals or {})
        self.epoch = 0
        self.leader_id: Optional[str] = None
        self.leader_epoch = -1

    @property
    def majority(self) -> int:
        return len(self.nodes) // 2 + 1

    def request_votes(self, candidate_id: str, epoch: Optional[int] = None) -> bool:
        """Start an election and return whether the candidate won a majority."""
        if candidate_id not in self.by_id or self.by_id[candidate_id].crashed:
            return False
        requested_epoch = self.epoch + 1 if epoch is None else epoch
        if requested_epoch < self.epoch:
            return False
        if requested_epoch > self.epoch:
            self.epoch = requested_epoch
            self.leader_id = None
            self.leader_epoch = -1

        votes = 0
        for voter in self.nodes:
            if voter.crashed:
                continue
            if voter.voted_epoch != self.epoch:
                voter.voted_epoch = self.epoch
                voter.voted_for = candidate_id
                votes += 1
            elif voter.voted_for == candidate_id:
                votes += 1

        if votes >= self.majority:
            self.leader_id = candidate_id
            self.leader_epoch = self.epoch
            return True
        return False

    def decide(self, proposal: Any, caller_id: str) -> Any:
        """Commit a proposed value; only the current epoch leader may call this.

        ``caller_id`` is mandatory and is always checked against the
        cluster's own tracked ``leader_id``/``leader_epoch`` — there is no
        way to omit or spoof it to bypass leader enforcement.
        """
        if (
            self.leader_id is None
            or self.leader_epoch != self.epoch
            or caller_id != self.leader_id
        ):
            raise RuntimeError("only the current epoch leader may decide")
        if proposal not in self.proposals.values():
            raise ValueError("decision must be one of the proposed values")

        voters = [node for node in self.nodes if not node.crashed]
        if len(voters) < self.majority:
            raise RuntimeError("not enough live voters for a majority")
        if any(node.decided is not None and node.decided != proposal for node in voters):
            raise RuntimeError("a voter already decided a conflicting value")

        # First persist to a quorum; then let every live voter learn that value.
        quorum = voters[:self.majority]
        for node in quorum:
            node.decided = proposal
        for node in voters[self.majority:]:
            if node.decided is not None and node.decided != proposal:
                raise RuntimeError("a voter already decided a conflicting value")
            node.decided = proposal
        return proposal


if __name__ == "__main__":
    nodes = [Node("n1"), Node("n2"), Node("n3")]
    proposals = {"n1": "alice", "n2": "bob", "n3": "carol"}
    out = buggy_decide(nodes, proposals)
    print("buggy:", out)
    assert len(set(out.values())) > 1  # setup demonstrates disagreement
    print("BUG: nodes decided different values")

    nodes = [Node("n1"), Node("n2"), Node("n3")]
    cluster = ConsensusCluster(nodes, proposals)
    assert cluster.request_votes("n1", epoch=1)
    assert cluster.leader_id == "n1"
    assert not cluster.request_votes("n2", epoch=1)
    assert cluster.request_votes("n2", epoch=2)  # higher epoch supersedes n1
    assert cluster.leader_id == "n2"
    try:
        cluster.decide("alice", caller_id="n1")  # lower-epoch n1 cannot finalize
    except RuntimeError:
        pass
    else:
        raise AssertionError("stale leader finalized a decision")
    # Leader enforcement: a node that was never elected cannot finalize either,
    # even though it isn't a stale ex-leader with a conflicting decision yet.
    try:
        cluster.decide("bob", caller_id="n3")
    except RuntimeError:
        pass
    else:
        raise AssertionError("non-leader caller finalized a decision")
    cluster.decide("bob", caller_id="n2")

    # Agreement: every live voter learns one identical value.
    assert {node.decided for node in nodes} == {"bob"}
    # Integrity: deciding again cannot change an already decided value.
    before = [node.decided for node in nodes]
    try:
        cluster.decide("carol", caller_id="n2")
    except RuntimeError:
        pass
    else:
        raise AssertionError("a node changed its mind")
    assert [node.decided for node in nodes] == before
    # Validity: the decided value was proposed by a participant, and decide()
    # itself rejects an un-proposed value rather than just asserting on it.
    assert all(node.decided in proposals.values() for node in nodes)
    try:
        cluster.decide("dave", caller_id="n2")
    except ValueError:
        pass
    else:
        raise AssertionError("un-proposed value was accepted")
    # Termination: a majority can decide despite one crashed node.
    nodes = [Node("a"), Node("b"), Node("c", crashed=True)]
    available = ConsensusCluster(nodes, {"a": "seat-a", "b": "seat-b", "c": "seat-c"})
    assert available.request_votes("a")
    available.decide("seat-a", caller_id="a")
    assert [node.decided for node in nodes[:2]] == ["seat-a", "seat-a"]
    print("consensus: agreement, integrity, validity, termination")
