#!/usr/bin/env python3
"""A small, executable Raft-style shared-log model."""
from dataclasses import dataclass, field
from typing import List, Optional


@dataclass(frozen=True)
class Entry:
    term: int
    value: str


@dataclass
class Replica:
    id: str
    log: List[Entry] = field(default_factory=list)
    current_term: int = 0
    voted_for: Optional[str] = None
    commit_index: int = -1
    live: bool = True

    def last_position(self):
        if not self.log:
            return (0, -1)
        return (self.log[-1].term, len(self.log) - 1)


class SharedLog:
    def __init__(self, replicas: List[Replica]):
        self.replicas = {replica.id: replica for replica in replicas}
        self.current_term = 0
        self.leader_id: Optional[str] = None

    def elect(self, candidate: str, term: int) -> str:
        if term <= self.current_term:
            raise ValueError("stale election term")
        node = self.replicas[candidate]
        if not node.live:
            raise ValueError("dead candidate")

        # Each live voter handles the term, prior vote, and freshness checks
        # independently; there is no arbitrary first-N quorum.
        votes = 0
        candidate_position = node.last_position()
        for voter in self.replicas.values():
            if not voter.live:
                continue
            if voter.current_term > term:
                raise ValueError("candidate term is stale for a voter")
            if voter.current_term < term:
                voter.current_term = term
                voter.voted_for = None
            if voter.voted_for is not None and voter.voted_for != candidate:
                continue
            if candidate_position < voter.last_position():
                continue
            voter.voted_for = candidate
            votes += 1
        if votes <= len(self.replicas) // 2:
            raise ValueError("election has no majority")
        self.current_term = term
        self.leader_id = candidate
        node.current_term = term
        return candidate

    def _catch_up(self, follower: Replica, leader: Replica) -> None:
        if not follower.live:
            return
        common = 0
        while common < len(follower.log) and common < len(leader.log):
            if follower.log[common] != leader.log[common]:
                break
            common += 1
        # Anything before common is matching. A mismatch at or before the
        # local commit point can never be repaired by overwriting history.
        if common <= follower.commit_index:
            if (common >= len(leader.log)
                    or common >= len(follower.log)
                    or follower.log[common] != leader.log[common]):
                raise ValueError("repair would overwrite committed history")
        if len(follower.log) > common:
            if common - 1 < follower.commit_index:
                raise ValueError("repair would truncate committed history")
            follower.log = follower.log[:common]
        follower.log.extend(leader.log[common:])

    def append(self, value: str, acknowledgements: Optional[List[str]] = None,
               leader_id: Optional[str] = None) -> int:
        if self.leader_id is None:
            raise ValueError("no elected leader")
        if leader_id is not None and leader_id != self.leader_id:
            raise ValueError("caller is not the elected leader")
        leader = self.replicas[self.leader_id]
        if not leader.live:
            raise ValueError("leader is not live")
        if leader.current_term != self.current_term:
            raise ValueError("leader has stale term")
        entry = Entry(self.current_term, value)
        leader.log.append(entry)
        targets = (set(acknowledgements) if acknowledgements is not None
                   else {r.id for r in self.replicas.values() if r.live})
        acked = {leader.id}
        for node_id in targets:
            if node_id == leader.id or node_id not in self.replicas:
                continue
            follower = self.replicas[node_id]
            if not follower.live or follower.current_term > self.current_term:
                continue
            follower.current_term = self.current_term
            try:
                self._catch_up(follower, leader)
            except ValueError:
                continue
            if follower.log and follower.log[-1] == entry:
                acked.add(follower.id)
        if len(acked) <= len(self.replicas) // 2:
            # No commit index was changed. The leader's suffix is deliberately
            # left uncommitted, as it would be in a real failed replication.
            raise ValueError("append did not reach a majority")
        for node_id in acked:
            replica = self.replicas[node_id]
            replica.commit_index = max(replica.commit_index, len(leader.log) - 1)
        return len(leader.log) - 1

    def read_from(self, node: str, offset: int) -> List[str]:
        replica = self.replicas[node]
        end = min(replica.commit_index, len(replica.log) - 1)
        return [entry.value for entry in replica.log[offset:end + 1]]


if __name__ == "__main__":
    # The original setup demonstrates the bug.
    class OldReplica:
        def __init__(self):
            self.log = []
        def append_local(self, entry):
            self.log.append(entry)
    a0, b0, c0 = OldReplica(), OldReplica(), OldReplica()
    a0.append_local("W1")
    b0.append_local("W2")
    c0.append_local("W1")
    print(a0.log, b0.log, c0.log)
    assert a0.log != b0.log
    print("BUG: logs diverged — not total order broadcast")

    a, b, c = Replica("a"), Replica("b"), Replica("c")
    cluster = SharedLog([a, b, c])
    assert cluster.elect("a", 1) == "a"
    first = cluster.append("W1")
    second = cluster.append("W2")
    assert (first, second) == (0, 1)
    assert cluster.read_from("a", 0) == ["W1", "W2"]
    assert cluster.read_from("b", 0) == ["W1", "W2"]
    assert a.commit_index == 1 and b.commit_index == 1
    assert c.commit_index == 1
    assert [r.commit_index for r in (a, b, c)] == [1, 1, 1]

    # A restricted acknowledgement set cannot commit, and does not advance
    # any local commit index.
    before = [r.commit_index for r in (a, b, c)]
    try:
        cluster.append("UNCOMMITTED", acknowledgements=["a"])
    except ValueError:
        pass
    else:
        raise AssertionError("minority append unexpectedly committed")
    assert [r.commit_index for r in (a, b, c)] == before
    try:
        cluster.replicas["b"].current_term = 99
        cluster.append("REJECTED", acknowledgements=["a"])
    except ValueError:
        pass
    finally:
        cluster.replicas["b"].current_term = cluster.current_term
        cluster.replicas["b"].voted_for = None
    assert cluster.leader_id == "a"

    # Fail over after W1 is majority-replicated. b is the only candidate with
    # the committed prefix available to the live voters.
    a.live = False
    assert cluster.elect("b", 2) == "b"
    try:
        a.live = True
        cluster.append("OLD-LEADER", acknowledgements=["a", "b", "c"],
                       leader_id="a")
    except ValueError:
        pass
    else:
        raise AssertionError("old/dead leader was accepted")
    # Give c a conflicting, uncommitted suffix and repair it from b.
    c.log.append(Entry(1, "BAD"))
    c.commit_index = 0
    cluster._catch_up(c, b)
    assert [e.value for e in c.log] == ["W1", "W2"]
    assert c.commit_index == 0
    # The committed prefix itself cannot be overwritten.
    saved = c.log[0]
    c.log[0] = Entry(9, "CORRUPT")
    try:
        cluster._catch_up(c, b)
    except ValueError:
        pass
    else:
        raise AssertionError("repair overwrote committed prefix")
    c.log[0] = saved
    cluster._catch_up(c, b)
    assert cluster.append("W3", acknowledgements=["b", "c"]) == 2
    assert cluster.read_from("c", 0) == ["W1", "W2", "W3"]
    assert cluster.read_from("b", 0)[0] == "W1"  # single-value consensus
    print("PASS: ordered majority log, term elections, repair, and failover")
